+          : null,
+        `Files: ${status.files}`,
+        `Chunks: ${status.chunks}`,
+        `Dirty: ${status.dirty ? "yes" : "no"}`,
+        `Index: ${status.dbPath}`,
+      ].filter(Boolean) as string[];
+      if (status.fallback?.reason) {
